#include <bits/stdc++.h>
using namespace std;

const int N=1e5+5,INF=0x3f3f3f3f;

struct Node{
    int l,r,val,dat;
    int cnt,siz;
}a[N];

int n,tot,root;

void output(){
    printf("%d\n",root);
    for(int i=1;i<=tot;i++)
        printf("%d %d %d\n",a[i].l,a[i].r,a[i].dat);
    puts("");
}

int New(int x){
    tot++;
    a[tot].l=a[tot].r=0;//赋值运算符是从右往左的！所以要先 ++tot，不是在 [] 中 ++tot!
    a[tot].val=x,a[tot].dat=rand();
    a[tot].cnt=a[tot].siz=1;
    return tot;
}

void Update(int p){
	if(!p)
		return;
    a[p].siz=a[a[p].l].siz+a[p].cnt+a[a[p].r].siz;
}

void build(){
    a[0].l=a[0].r=a[0].val=a[0].dat=a[0].cnt=a[0].siz=0;
    New(INF);
    New(-INF);
    a[1].l=2,root=1,Update(1);
    //要及时 Update!!!
}

void zig(int &p){
    if(!p)
        return;
    int q=a[p].l;
    a[p].l=a[q].r,a[q].r=p,p=q;
    Update(a[p].r),Update(p);
}

void zag(int &p){
    if(!p)
        return;
    int q=a[p].r;
    a[p].r=a[q].l,a[q].l=p,p=q;
    Update(a[p].l),Update(p);
}

void Insert(int &p,int val){
    if(!p)
        p=New(val);
    else if(a[p].val==val)
        a[p].cnt++;
    else if(a[p].val<val){
        Insert(a[p].r,val);
        if(a[a[p].r].dat>a[p].dat)
            zag(p);
    }else if(a[p].val>val){
        Insert(a[p].l,val);
        if(a[a[p].l].dat>a[p].dat)
            zig(p);
    }
    Update(p);
    //output();
}

void Remove(int &p,int x){
	if(!p)
		return;
    if(a[p].val==x){
        if(a[p].cnt>1){
            a[p].cnt--,Update(p);
            return;
        }
        if(a[p].l || a[p].r){
        	if(!a[p].r || a[a[p].l].dat>a[a[p].r].dat)
            	zig(p),Remove(a[p].r,x);
        	else
            	zag(p),Remove(a[p].l,x);
            Update(p);
        }else
        	p=0;
        return;
    }
    if(a[p].val<x)
    	Remove(a[p].r,x);
    else
    	Remove(a[p].l,x);
    Update(p);
}

int Get_Rank(int p,int x){
    if(!p)
        return 0;
    if(a[p].val<x)
        return a[a[p].l].siz+a[p].cnt+Get_Rank(a[p].r,x);
    if(a[p].val==x)
        return a[a[p].l].siz;
    if(a[p].val>x)
        return Get_Rank(a[p].l,x);
}

int Get_Val(int p,int x){
    if(!p)
        return INF;
    if(a[a[p].l].siz>=x)
        return Get_Val(a[p].l,x);
    if(a[a[p].l].siz+a[p].cnt>=x)
        return a[p].val;
    return Get_Val(a[p].r,x-a[a[p].l].siz-a[p].cnt);
}

int Get_Pre(int p,int x){
    int ans=-INF;
    while(p){
        if(a[p].val>=x)
            p=a[p].l;
        else
            ans=max(ans,a[p].val),p=a[p].r;
    }
    return ans;
}

int Get_Nxt(int p,int x){
    int ans=INF;
    while(p){
        if(a[p].val<=x)
            p=a[p].r;
        else
            ans=min(ans,a[p].val),p=a[p].l;
    }
    return ans;
}

int main(){
    srand(time(NULL));
    scanf("%d",&n);
    build();
    //output();
    while(n--){
        int op,x;
        cin>>op>>x;
        if(op==1)
            Insert(root,x);
        else if(op==2)
            Remove(root,x);
        else if(op==3)
            printf("%d\n",Get_Rank(root,x));
        else if(op==4)
            printf("%d\n",Get_Val(root,x+1));//操作 3,4 要算上哨兵
        else if(op==5)
            printf("%d\n",Get_Pre(root,x));
        else if(op==6)
            printf("%d\n",Get_Nxt(root,x));
        //output();
    }
    return 0;
}
